      function nextStream () {
        _read = null
        read(null, function (end, stream) {
          if(end)
            return cb(end)
          if(stream && 'object' === typeof stream)
            stream = values(stream)
          else if ('function' !== typeof stream)
            stream = once(stream)
          _read = stream
          nextChunk()
